var e=JSON.parse(`[{"id":"L5_1","type":"dialog","speaker":"CHILDREN_BARCODE_TWO_NULL","text":{"KOREA":"아인, 이것 봐~ 나 엄청 작은 물고기를 잡았어~","JPN":"アイン、みてみて～！　ぼく、すっごく小さいお魚さんを捕まえたの～！","ENG":"Look, Eins! I caught a tiny teeny fish!","TWN":"艾茵你看～我抓到一條超小的魚欸～"},"stage":{"bg":"CRUISE","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHILDREN_BARCODE_ONE_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"CHILDREN_BARCODE_TWO_NULL","face":"UNIT_LAUGH"}}}},{"id":"L6_1","type":"dialog","speaker":"CHILDREN_BARCODE_ONE_NULL","text":{"KOREA":"흥, 겨우 그 정도 가지고? 내가 잡은 물고기는 엄청엄청 작거든?","JPN":"ふん、それくらいで？　あたしが捕まえたお魚のほうがもっともっと小さいよ？","ENG":"Hmph! That's nothing! I caught a tiny teeny weeny fish!","TWN":"拜託～才這樣喔？我抓到的魚才是宇宙無敵小呢！"},"stage":{"bg":"CRUISE","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHILDREN_BARCODE_ONE_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHILDREN_BARCODE_TWO_NULL","face":"UNIT_LAUGH"}}}},{"id":"L7_1","type":"dialog","speaker":"CHILDREN_BARCODE_ONE_NULL","text":{"KOREA":"짜잔. 어때? 손바닥에 들어올 만큼 작지?","JPN":"ジャジャーン！　どう？　手のひらよりも小さいでしょ？","ENG":"Tah-dah. See? It's small enough to fit in my palm!","TWN":"鏘鏘～怎麼樣？小到我可以一手掌握喔！"},"stage":{"bg":"CRUISE","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHILDREN_BARCODE_ONE_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"CHILDREN_BARCODE_TWO_NULL","face":"UNIT_LAUGH"}}}},{"id":"L8_1","type":"dialog","speaker":"CHILDREN_BARCODE_TWO_NULL","text":{"KOREA":"우와아~ 그럼 난 엄청엄청엄~청 작은 물고기를 잡을래!","JPN":"うわあ～！　じゃあ、ぼくはもっともっともーっと小さいお魚さんを捕まえる！","ENG":"Wow! Then I'm gonna catch a tiny teeny weeny itsy-bitsy fish!","TWN":"哇哇～那我也要抓一條超～～～級小的魚！"},"stage":{"bg":"CRUISE","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHILDREN_BARCODE_ONE_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"CHILDREN_BARCODE_TWO_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"CHILDREN_BARCODE_ONE_NULL","text":{"KOREA":"이익! 너 거기 서! 내가 자꾸 따라하지 말랬지!","JPN":"ええ！　もう！　何でも真似しないでって言ったでしょ！","ENG":"Argh! Stop right there! I told you to stop copying me!","TWN":"喂！你別動！不是叫你不要一直當跟屁蟲嗎！"},"stage":{"bg":"CRUISE","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHILDREN_BARCODE_ONE_NULL","face":"UNIT_SERIOUS"},"C":null,"R":null}}},{"id":"L14_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"…….","TWN":"……"},"stage":{"bg":"CRUISE","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L16_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ffd34c>잔여 동력 5.7%. 정보 오염에 대비하기 위한 동력이 확보되었습니다.</color>","JPN":"<color=#ffd34c>残余エネルギー5.7％。情報汚染に備えるためのエネルギーを確保しました。</color>","ENG":"<color=#ffd34c>Current remaining power is at 5.7%. Adequate power secured to guard against data corruption.</color>","TWN":"<color=#ffd34c>剩餘動能 5.7%。預防情報污染的動能無虞。</color>"},"stage":{"bg":"CRUISE","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_BEEP"},{"id":"L17_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ffd34c>동력 효율성 조정을 위해 안전 모드로 전환합니다.</color>","JPN":"<color=#ffd34c>動力効率性の調整のため、安全モードに切り替えます。</color>","ENG":"<color=#ffd34c>Switching to safe mode to recalibrate power efficiency.</color>","TWN":"<color=#ffd34c>將轉換成安全模式以調整動能效率。</color>"},"stage":{"bg":"CRUISE","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"여기는…….","JPN":"ここは……","ENG":"Where am I…?","TWN":"這裡是……"},"stage":{"bg":"CRUISE","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"CHILDREN_BARCODE_TWO_NULL","text":{"KOREA":"앗! 접시 머리 언니가 일어났어!","JPN":"あっ！　お皿頭のお姉ちゃんが起きた！","ENG":"Ooh! The dish head lady woke up!","TWN":"喔！盤子姊姊醒咧！"},"stage":{"bg":"CRUISE","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"CHILDREN_BARCODE_TWO_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L22_1","type":"dialog","speaker":"CHILDREN_BARCODE_ONE_NULL","text":{"KOREA":"정말? 그럼 내가 먼저 알려 줘야지~","JPN":"ホントだ！　あたしが一番先に知らせよーっと！","ENG":"Really? Then I'm gonna tell her first!","TWN":"真的嗎？那我要趕快去跟姊姊說～"},"stage":{"bg":"CRUISE","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHILDREN_BARCODE_ONE_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"CHILDREN_BARCODE_TWO_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L25_1","type":"dialog","speaker":"CHILDREN_BARCODE_TWO_NULL","text":{"KOREA":"앗, 그럼 츠바이도 알려 줄래~","JPN":"えっ、ぼくもいくー！","ENG":"Ooh, me too!","TWN":"喔！那茨粨也要去跟姊姊說～"},"stage":{"bg":"CRUISE","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"CHILDREN_BARCODE_TWO_NULL","face":"UNIT_LAUGH"}}}},{"id":"L28_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"여기는……. 대기가 존재하는 것으로 보아 바다 밑바닥은 아니군요.","JPN":"ここは……大気が存在することから海の底ではなさそうですね。","ENG":"I take it… that I'm no longer on the seabed, judging by the presence of a breathable atmosphere.","TWN":"這裡是……有空氣，那應該不是海底。"},"stage":{"bg":"CRUISE","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"혹시 휴먼들이 얘기하는 아틀란티스입니까?","JPN":"もしやここは、ヒューマンの間で有名なアトランティスでしょうか？","ENG":"Is this perhaps the legendary Atlantis that humans speak of?","TWN":"是人類說的亞特蘭堤斯嗎？"},"stage":{"bg":"CRUISE","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"LUCID_BARCODE_NULL_NULL","text":{"KOREA":"죄송해요. 아틀란티스는 아니지만……. 바닷속보다는 안전한 곳이에요.","JPN":"すみません。アトランティスではありませんが……海の中よりは安全な場所だと思います。","ENG":"Sorry. It's no Atlantis… but it sure is much safer than the bottom of the ocean.","TWN":"抱歉，這裡不是亞特蘭堤斯……但是比海裡安全的地方。"},"stage":{"bg":"CRUISE","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCID_BARCODE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"LUCID_BARCODE_NULL_NULL","text":{"KOREA":"저기……. 몸은 좀 괜찮으세요?","JPN":"あの……具合はいかがですか？","ENG":"So, um… How are you feeling?","TWN":"請問……你的身體還好嗎？"},"stage":{"bg":"CRUISE","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCID_BARCODE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"……생체 정보. 확인.","JPN":"……生体情報、確認。","ENG":"Biometrics… identified.","TWN":"……生物資訊確認。"},"stage":{"bg":"CRUISE","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"의외로군요. 당신이 저를 바다에서 인양하셨습니까.","JPN":"意外ですね。あなたが私を海から引き揚げたのですか？","ENG":"Things took a rather unexpected turn of events. Did you salvage me from the sea?","TWN":"真是意外，是你把我從海裡打撈上來的嗎？"},"stage":{"bg":"CRUISE","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"LUCID_BARCODE_NULL_NULL","text":{"KOREA":"아, 네. 혹시나 계속 바닷속에 머물고 싶으셨다면……. 죄송해요.","JPN":"あ、はい。もしかしてずっと海の中にいたかったのなら……すみません。","ENG":"Oh… Yes. Would you have rather stayed there…? I apologize, if that's the case.","TWN":"嗯，對，還是其實你想繼續待在海裡……不好意思。"},"stage":{"bg":"CRUISE","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LUCID_BARCODE_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L38_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"아닙니다. 진공관께서 이 땅에 탄생하신 이래 우리 기계와 바닷물은 오랜 상극 관계를 이어 왔으니까요.","JPN":"いいえ。真空管様がこの地に誕生して以来、我々機械と海水は長きにわたり相反する関係でした。","ENG":"No need for an apology. Ever since the first great diode existed upon this land, we machines have maintained a notoriously adverse relationship with sea water.","TWN":"不，自從真空管在這塊土地上誕生後，我們機器和海水就是水火不容的。"},"stage":{"bg":"CRUISE","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LUCID_BARCODE_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L39_1","type":"dialog","speaker":"LUCID_BARCODE_NULL_NULL","text":{"KOREA":"그, 그렇군요. 제가 아직 세상 일은 잘 몰라서……. 죄송해요.","JPN":"そ、そうだったんですね。まだ世間のことはあまりわかっていなくて……すみません。","ENG":"I-I see. I'm not so familiar with how the world works yet… I'm sorry.","TWN":"原…原來是這樣，我對世界上的事還不是很清楚……不好意思。"},"stage":{"bg":"CRUISE","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LUCID_BARCODE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L40_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"왜 계속 죄송해합니까, 휴먼.","JPN":"なぜずっと謝るのですか、ヒューマン。","ENG":"Why do you keep apologizing, human?","TWN":"人類，你幹嘛一直不好意思？"},"stage":{"bg":"CRUISE","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LUCID_BARCODE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L41_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"인양 비용을 고려하면 당신은 현재 <color=#ffd34c>갑</color>입니다. 조금 더 세게 나와 주시죠.","JPN":"引き揚げ費用を考慮すると、あなたは現在<color=#ffd34c>甲</color>の立場です。もっと強く出てください。","ENG":"Considering the cost of salvage operations, you're the one with the <color=#ffd34c>clout</color> between us. I must insist you behave more boldly.","TWN":"考慮到打撈的費用，你現在應該可以算是<color=#ffd34c>債權人</color>，氣勢可以再高張一點。"},"stage":{"bg":"CRUISE","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LUCID_BARCODE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L44_1","type":"dialog","speaker":"CHILDREN_BARCODE_ONE_NULL","text":{"KOREA":"우리 언니는 나쁜 말 안 해. 교실에 거미가 들어와도 운동장 나무에 데려다 주는 사람이니까.","JPN":"お姉ちゃんはとても優しい人なの。教室にクモが入ってきても、庭の木まで移してあげる人なんだから。","ENG":"Big sis never says anything bad. She's so sweet she'd take a spider to the tree in the school yard if she found one in the classroom.","TWN":"我姊姊才不是這種人，她連有蜘蛛跑到教室裡，她也會帶到操場的樹上上去放生喔！"},"stage":{"bg":"CRUISE","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHILDREN_BARCODE_ONE_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHILDREN_BARCODE_TWO_NULL","face":"UNIT_LAUGH"}}}},{"id":"L45_1","type":"dialog","speaker":"CHILDREN_BARCODE_TWO_NULL","text":{"KOREA":"아인은 거미 보고 울었어~","JPN":"アインはクモを見てビビって泣いちゃったもんね～","ENG":"Eins cried when she saw the spider!","TWN":"艾茵看到蜘蛛還哭了喔～"},"stage":{"bg":"CRUISE","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHILDREN_BARCODE_ONE_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHILDREN_BARCODE_TWO_NULL","face":"UNIT_IDLE"}}}},{"id":"L46_1","type":"dialog","speaker":"CHILDREN_BARCODE_ONE_NULL","text":{"KOREA":"드, 드라이도 울었잖아! 네가 얼굴에 들이밀어서 그렇지!","JPN":"ド、ドライだって泣いてたもん！　目の前に突き出されてびっくりしただけだもん！","ENG":"S-so did Drei! I only cried because you shoved it in my face!","TWN":"特…特蘿伊還不是有哭！都嘛是因為你拿蜘蛛嚇我們！"},"stage":{"bg":"CRUISE","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHILDREN_BARCODE_ONE_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"CHILDREN_BARCODE_TWO_NULL","face":"UNIT_IDLE"}}}},{"id":"L47_1","type":"dialog","speaker":"CHILDREN_BARCODE_TWO_NULL","text":{"KOREA":"울보래요~ 울보래요~ 아인은 울보래요~","JPN":"泣き虫♪　泣き虫♪　アインは泣き虫♪","ENG":"You're such a crybaby, Eins!","TWN":"愛哭鬼～愛哭鬼～艾茵是愛哭鬼～"},"stage":{"bg":"CRUISE","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHILDREN_BARCODE_ONE_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"CHILDREN_BARCODE_TWO_NULL","face":"UNIT_IDLE"}}}},{"id":"L49_1","type":"dialog","speaker":"CHILDREN_BARCODE_ONE_NULL","text":{"KOREA":"너어! 거기 서!","JPN":"もう！　ツヴァイ！　","ENG":"Hey! Stop right there!","TWN":"你！你別跑！"},"stage":{"bg":"CRUISE","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHILDREN_BARCODE_ONE_NULL","face":"UNIT_SERIOUS"},"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":"LUCID_BARCODE_NULL_NULL","text":{"KOREA":"얘, 얘들아. 배 위에서 뛰어다니면 할아버지한테 혼나.","JPN":"ちょ、ちょっと二人とも。船の上で走り回ったらおじいさんに怒られるよ。","ENG":"N-now, now, girls… Grandpa will scold you if you run around on the ship.","TWN":"你們，不可以在船上奔跑，爺爺會生氣喔。"},"stage":{"bg":"CRUISE","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LUCID_BARCODE_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L4_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"생체 정보 분석 결과, 저 아이들과 친족은 아니군요. 보호자 신분입니까.","JPN":"生体情報分析の結果、あの子たちと血の繋がりはないようですね。保護者ですか。","ENG":"My biometric analysis suggests that you are not their biological kin. Are you their legal guardian, perhaps?","TWN":"生物資訊分析結果。你和她們沒有親屬關係，你是她們的保護人嗎？"},"stage":{"bg":"CRUISE","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LUCID_BARCODE_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L5_1","type":"dialog","speaker":"LUCID_BARCODE_NULL_NULL","text":{"KOREA":"아, 네. 일단은 저 아이들의 선생님으로 일하고 있는 중이에요.","JPN":"あ、はい。一応あの子たちの先生として働かせてもらっています。","ENG":"Oh, yes. I'm serving as their teacher for now.","TWN":"是的，我現在的工作是她們的老師。"},"stage":{"bg":"CRUISE","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LUCID_BARCODE_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L6_1","type":"dialog","speaker":"LUCID_BARCODE_NULL_NULL","text":{"KOREA":"그러고 보니 제 소개가 늦었네요. 루시드라고 불러 주세요, 호라이즌 씨.","JPN":"そういえば自己紹介が遅れてしまいました。ルシードと呼んでください、ホライズンさん。","ENG":"Oh, where are my manners. I forgot to introduce myself. Please call me Lucid, Ms. Horizon.","TWN":"這麼說來，我還沒自我介紹對吧？地平線小姐，我叫露西德。"},"stage":{"bg":"CRUISE","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LUCID_BARCODE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"……제 이름을 어디서 들었습니까, 휴먼?","JPN":"……私の名前はどこで聞いたのですか、ヒューマン？","ENG":"…Who told you my name, human?","TWN":"……人類，你從哪裡聽到我的名字的？"},"stage":{"bg":"CRUISE","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"LUCID_BARCODE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"그렇게 경계하지 마시죠, 사채업자. 그 분들은 당신에 대해 알 자격이 있답니다.","JPN":"そんなに警戒しないでいただきたいですわ、闇金業者さん。その方たちはあなたについて知る資格があります。","ENG":"There's no need to get so defensive, loan shark girl. They have every right to know about you.","TWN":"放高利貸的，你不用那麼緊張。她們有資格知道關於你的事。"},"stage":{"bg":"CRUISE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"LUCID_BARCODE_NULL_NULL","text":{"KOREA":"아, 죄송해요. 팬드래건 님. 티타임에 너무 소란스러웠죠.","JPN":"あっ、すみませんペンドラゴン様。ティータイムなのにうるさくしてしまって。","ENG":"Oh, I apologize, Lady Pendragon. I didn't mean to intrude upon your teatime with all this ruckus.","TWN":"抱歉，潘德拉貢小姐，打擾你的下午茶時間。"},"stage":{"bg":"CRUISE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"LUCID_BARCODE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"사죄의 말은 아껴 두세요, 루시드 양.","JPN":"謝罪の言葉は必要ありませんわ、ルシードさん。","ENG":"Save your apologies for when you really need them, Ms. Lucid.","TWN":"露西德小姐，不需要這麼客氣。"},"stage":{"bg":"CRUISE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"때로는 소란스러운 분위기 속에서 홍차의 여운을 즐기는 것도 제 낙이랍니다.","JPN":"時には騒がしい雰囲気の中で紅茶の味を堪能するのも一興ですもの。","ENG":"Relishing in the subtle placidity of a cup of tea amidst such a ruckus as this is one of my small pleasures.","TWN":"有時候在熱鬧的氣氛中，品味紅茶的茶韻也是我的樂趣之一。"},"stage":{"bg":"CRUISE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"LUCID_BARCODE_NULL_NULL","text":{"KOREA":"그, 그렇군요. 홍차의 세계는 정말 심오하네요…….","JPN":"そ、そうなんですね。紅茶の世界は実に奥深いものですね……","ENG":"I-I see. I still have much to learn about the wonders of tea, I suppose…","TWN":"原…原來如此，紅茶的世界真是深奧……"},"stage":{"bg":"CRUISE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"LUCID_BARCODE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"이쪽은 어린이집 교사, 그쪽은 홍차 외판원이십니까?","JPN":"こちらは幼稚園の教員、そちらは紅茶のセールスマンですか？","ENG":"So she's a pre-school teacher. And you? Are you a tea peddler?","TWN":"這位是幼稚園老師，請問那位是賣紅茶的嗎？"},"stage":{"bg":"CRUISE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LUCID_BARCODE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"카운터 아카데미의 요청으로 크루즈 유람 체험 교육을 진행하게 된 엘리자베스 팬드래건이랍니다.","JPN":"カウンターアカデミーの要請を受け、クルーズ遊覧体験教育の進行役を勤めているエリザベス・ペンドラゴンと申します。","ENG":"I am Elizabeth Pendragon, currently chaperoning the educational cruise ship tour at the behest of the Counter Academy.","TWN":"我是受制裁者學院之邀，策畫郵輪體驗校外教學的伊莉莎白·潘德拉貢。"},"stage":{"bg":"CRUISE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"<color=#ffd34c>콜드 케이스</color>를 건지는 건 제가 제출했던 커리큘럼에 없었지만 말이죠.","JPN":"<color=#ffd34c>コールドケース</color>を引き揚げるのは私が提出したカリキュラムにはありませんでしたが。","ENG":"Although I must admit, fishing a <color=#ffd34c>Cold Case</color> out of the water was not part of the curriculum I recommended.","TWN":"不過打撈<color=#ffd34c>Cold Case</color>的行程，並不在我提交的規劃裡。"},"stage":{"bg":"CRUISE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"…….","TWN":"……"},"stage":{"bg":"CRUISE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"RYAN_PRYDWEN_NULL_NULL","text":{"KOREA":"아가씨. 민감한 이야기는 자리를 옮겨서 하시죠.","JPN":"お嬢様、大事な話は場所を移してからなさるのはいかがでしょうか。","ENG":"My Lady. Perhaps we should discuss such sensitive subjects elsewhere.","TWN":"小姐，敏感的話題還是先換個地方再說吧。"},"stage":{"bg":"CRUISE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"RYAN_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L27_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"그래야겠군요. 한창 성장 중인 아이들이 들어서 좋을 것 없을 테니까요.","JPN":"ええ。成長期の子どもたちが聞いて楽しい話ではないでしょう。","ENG":"You're quite right. Nothing good can come of innocent children stumbling upon such jabber.","TWN":"你說的沒錯，這些話不適合讓孩子們聽到。"},"stage":{"bg":"CRUISE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RYAN_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L28_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"이 배에는 다양한 시설이 있답니다. 그중에는 아주 조용한 장소도 있죠.","JPN":"この船には様々な施設がありますわ。その中にはとても静かな場所もあります。","ENG":"This ship is furnished with a wide variety of facilities. Including very quiet, private spaces.","TWN":"這艘船上有各式各樣的設施，當中也有非常安靜的空間。"},"stage":{"bg":"CRUISE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RYAN_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L29_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"어떤가요, 호라이즌 양?","JPN":"いかがでしょう、ホライズンさん？","ENG":"Would you do us the honor, Ms. Horizon?","TWN":"地平線小姐，你怎麼說呢？"},"stage":{"bg":"CRUISE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RYAN_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L31_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"동의합니다. 행동 방침은 이야기를 들은 뒤에 결정하죠.","JPN":"同意します。行動方針は話を聞いてから決めます。","ENG":"Agreed. I will defer determining my course of action until after this discussion.","TWN":"同意，下一步行動就等聽你說完再決定。"},"stage":{"bg":"CRUISE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"퓨처 앳 워 콜드 케이스 137번. 별칭 <color=#ffd34c>자동인형</color>.","JPN":"フューチャーアットウォーコールドケースNo.137。別称、<color=#ffd34c>自動人形</color>。","ENG":"Future-at-War Cold Case No. 137. A.k.a. <color=#ffd34c>Automaton</color>.","TWN":"天啟兵器 Cold Case 137號。代號 <color=#ffd34c>自動機器人</color>。"},"stage":{"bg":"DOCUMENTS","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L38_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"등신대 인형으로서, 내부는 생산년도와 생산지를 확인할 수 없는 기계부품으로 구성되어 있다…….","JPN":"等身大の人形で、内部は生産年度と生産地が確認できない機械部品で構成されている……","ENG":"A life-size doll fitted with mechanical parts of unknown origin and year of production…","TWN":"等身大小，內部是由無法確認製造日期和產地的機器零件所組成……"},"stage":{"bg":"DOCUMENTS","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L39_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"주목할 만한 기능을 확인할 수 없어 연구 보류.","JPN":"注目すべき機能が確認できないため、研究は保留。","ENG":"No notable features verified. Further research suspended.","TWN":"無法確認值得注意的功能，需再研究。"},"stage":{"bg":"DOCUMENTS","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L40_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"이상이 엠버 소장이 국제연합군에 제출했던 보고서랍니다.","JPN":"以上がアンバー所長が国連軍に提出した報告書の内容です。","ENG":"That's what Director Ember wrote in her report to the Multinational Coalition Force.","TWN":"以上是琥珀所長提供給國際聯合軍隊的報告內容。"},"stage":{"bg":"DOCUMENTS","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L41_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"저라면 이런 소박한 이름 대신 <color=#ffd34c>유해</color> 정도로 붙였겠네요.","JPN":"私ならこんな素朴な名前の代わりに<color=#ffd34c>遺骸</color>と名付けたでしょう。","ENG":"If it was me, I'd have simply labeled this exhibit something along the lines of <color=#ffd34c>remains</color>.","TWN":"要是我的話，才不會取這麼低調的名字，應該要取像是<color=#ffd34c>遺骸</color>這種才對。"},"stage":{"bg":"DOCUMENTS","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L42_1","type":"dialog","speaker":null,"text":{"TWN":"　　"},"stage":{"bg":"DOCUMENTS","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L44_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"체험 교육 진행자가 알아서는 안 될 내용을 알고 있군요. 퓨처 앳 워 관계자입니까.","JPN":"子どもの体験教育の担当者が\\n知っていてはいけない内容を知っていますね。\\nフューチャーアットウォーの関係者ですか。","ENG":"You know something that no school chaperone would be aware of. Are you affiliated with Future-at-War?","TWN":"校外教學的策畫人，怎麼會知道這麼多不該知道的事？你是天啟兵器的關係人嗎？"},"stage":{"bg":"LIBRARY_01","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"저희는 현실세계에 존재하는 아티팩트와 관련된 사안을 주의깊게 살피는 편이에요.","JPN":"私たちは現実世界に存在するアーティファクト関連の事案を注意深く調査しています。","ENG":"Let's just say we pay particularly close attention to information pertaining to artifacts that exist in the Normalside.","TWN":"我們一直都有在觀察人造神器在現世的情況。"},"stage":{"bg":"LIBRARY_01","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"퓨처 앳 워가 연구했던 콜드 케이스들도 예외는 아니랍니다.","JPN":"フューチャーアットウォーが研究していたコールドケースも例外ではありません。","ENG":"The Cold Cases studied by Future-at-War are no exception, of course.","TWN":"天啟兵器研究的Cold Case也不例外。"},"stage":{"bg":"LIBRARY_01","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"당시 개입하지 않았던 이유는 간단합니다. 관리국의 중재 때문이었죠.","JPN":"当時介入しなかった理由は簡単です。管理局の仲裁のせいでした。","ENG":"There's only one reason why we did not intervene back then. It was due to the arbitration of the Administration.","TWN":"而當時未介入的原因很簡單，因為管理局的仲裁。"},"stage":{"bg":"LIBRARY_01","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"우려대로, 많은 아티팩트가 퓨처 앳 워 계획이 공중분해 되면서 사라졌지만 말이에요.","JPN":"そして懸念どおり、多くのアーティファクトが\\nフューチャーアットウォー計画の空中分解によって消えてしまいました。","ENG":"Just as we feared, though, too many artifacts vanished into thin air when the Future-at-War plan fell through.","TWN":"雖然果真如我們所料，許多人造神器在天啟兵器計畫解散後消失不見。"},"stage":{"bg":"LIBRARY_01","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"그래서 저를 제압하고 프레임을 확보할 계획입니까, 휴먼?","JPN":"それで、私を制圧してフレームを確保する計画ですか、ヒューマン？","ENG":"Do you then plan to overpower me and take custody of the frame, human?","TWN":"所以你是想抓住我後拿走這副軀殼嗎，人類？"},"stage":{"bg":"LIBRARY_01","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"그럴 계획은 없어요, 호라이즌 양. 당분간은 말이죠.","JPN":"そういう計画はありませんわ、ホライズンさん。当分の間は、ですが。","ENG":"I have no such plans, Ms. Horizon. At least not yet.","TWN":"我沒這個意思……暫時……"},"stage":{"bg":"LIBRARY_01","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L3_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"그렇다면 어째서 이 바다 한복판에서 커뮤니케이션을 해야 하는지 의문이군요.","JPN":"では、なぜ私たちがこの海のど真ん中でコミュニケーションをしているのか疑問ですね。","ENG":"Then I do not see why we must hold this discourse in the middle of the ocean.","TWN":"那我們為何要在這大海中央談話呢？"},"stage":{"bg":"LIBRARY_01","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L4_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"제가 당신을 만나러 온 까닭은, 당신이 제프티 바이오테크와 대립하기 때문이에요.","JPN":"私があなたに会いに来た理由は、あなたがジェフティ・バイオテックと対立しているためです。","ENG":"I came to see you because you are currently at odds with Jehuty Biotech.","TWN":"我之所以會來找你，正是因為你和傑夫堤生物科技是對立的。"},"stage":{"bg":"LIBRARY_01","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L5_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"표면적으로는 합법적인 기업 같지만, 내부가 어떤지는…….","JPN":"表面上は合法的な企業に見えますが、内部がどうなのかは……","ENG":"Although they may appear to be a legitimate business on the outside…","TWN":"那間公司外表看似正派經營，但裡面呢……"},"stage":{"bg":"LIBRARY_01","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L6_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"당신도 이미 직접 확인해 보셨겠죠.","JPN":"あなたもすでに、ご自身の目で確かめたのでしょう。","ENG":"I'm sure you saw for yourself their true nature.","TWN":"你應該也親自確認過吧？"},"stage":{"bg":"LIBRARY_01","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"당신은 유능한 카운터로 추정됩니다만. 본인이 나설 계획은 없는 겁니까.","JPN":"あなたは有能なカウンターと推定されますが、自身で直接解決する計画はないのですか。","ENG":"You strike me as a capable Counter. Why not strike them yourself?","TWN":"我看你應該也是位出色的制裁者，你不打算親自出馬嗎？"},"stage":{"bg":"LIBRARY_01","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"제프티 바이오테크는 저희와 오랜 시간 마찰을 빚어 온 세력의 하부 조직이랍니다.","JPN":"ジェフティ・バイオテックは私たちと長い間軋轢を生んできた勢力の下部組織です。","ENG":"Jehuty Biotech is a subordinate organization of a faction with which we have a long history of conflict.","TWN":"傑夫堤生物科技，依附在與我們長期處不合的勢力底下。"},"stage":{"bg":"LIBRARY_01","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L9_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"안타깝지만, 혼란이 수습된 현재 그들과 전면전을 일으키는 건 부담이 크죠.","JPN":"残念ですが、混乱が収まった現在、彼らと全面戦争を起こすのは負担が大きいのです。","ENG":"Regrettably, waging an all-out war with them so immediately after the return of stability would bear many risks.","TWN":"可惜的是，混亂結束後，現在要和他們正面交鋒的話負擔太大。"},"stage":{"bg":"LIBRARY_01","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"그래서 <color=#ffd34c>오래된 목소리</color>의 조언대로 당신을 만나러 온 거예요.","JPN":"ですので、<color=#ffd34c>古き声</color>の助言どおりあなたに会いに来たのです。","ENG":"That's why we came to see you, per the advice of the <color=#ffd34c>Old Voice</color>.","TWN":"所以才會照著<color=#ffd34c>老聲音</color>的建議來找你。"},"stage":{"bg":"LIBRARY_01","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"휴먼들의 복잡한 갈등 관계를 이해하기 위해 시간을 소모하는 것은 거부하겠습니다.","JPN":"ヒューマンたちの複雑な対立関係を理解するために時間を消耗することは拒否します。","ENG":"I refuse to waste any time trying to understand such a complicated conflict between humans.","TWN":"我拒絕花時間理解人類間複雜的利弊關係。"},"stage":{"bg":"LIBRARY_01","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"저는 채무자와 정산만 마치면 됩니다. 당신들의 용병 노릇을 할 생각은 없습니다.","JPN":"私は債務者と精算さえ済ませればそれでいいです。あなたたちの傭兵になるつもりはありません。","ENG":"All I need to do is settle the account with my debtor. I have no desire to serve as your mercenary.","TWN":"我只想處理和債務人之間的債務，不打算成為你們的傭兵。"},"stage":{"bg":"LIBRARY_01","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"제 제안과 관계없이 저들을 무너뜨리겠다는 뜻으로 들리는군요.","JPN":"私の提案と関係なく、彼らを倒すという意味に聞こえますわね。","ENG":"That sounds like you'll bring them down regardless of my proposition.","TWN":"我的意思不是要你除掉他們。"},"stage":{"bg":"LIBRARY_01","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"…….","TWN":"……"},"stage":{"bg":"LIBRARY_01","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"딘 코너, 본명 윌버 웨이틀리 대표는 17시간 전 샤레이드 소재의 본사에 도착했어요.","JPN":"ディーン・コナー、本名ウィルバー・ウェイトリー代表は17時間前、シャレードの本社に到着しました。","ENG":"Dean Conner, real name Wilbur Whateley, arrived at his corporate HQ in Charade as of 17 hours ago.","TWN":"狄恩•康納，也就是韋爾伯·韋特利代表，在17小時前曾經造訪過位在查雷德的總公司。"},"stage":{"bg":"LIBRARY_01","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"아마 그곳에서 관리국의 보호를 받으며 농성할 생각이겠죠.","JPN":"おそらくそこで管理局の保護を受けながら立てこもるつもりでしょう。","ENG":"He will likely endure the siege there under the protection of the Administration.","TWN":"他可能是想取得管理局的保護後借題發揮。"},"stage":{"bg":"LIBRARY_01","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"건축물의 방호력 때문입니까?","JPN":"建築物の防護力を信じているからですか？","ENG":"Do the structures there provide him reliably protective shelter?","TWN":"是因為建築物的防護力嗎？"},"stage":{"bg":"LIBRARY_01","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"틀렸어요. 당신들과 이면세계를 탐사할 때 얻은 아티팩트 때문이랍니다.","JPN":"いいえ。あなたたちと裏世界を探査した際に手に入れたアーティファクトがあるからです。","ENG":"That's not it. He's counting on the artifact he acquired during his expedition to the Counterside with you.","TWN":"不是，是與你們勘查異界時取得的人造神器有關。"},"stage":{"bg":"CORRIDOR_04","bgm":"THEMA_PRYDWEN","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"SPIRA_CORRUPT_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"데몬 타입 침식체를 불러냈던 그 이상한 카메라 말이군요. 기록에 남아 있습니다.","JPN":"デーモンタイプ侵食体を呼び出したあの不思議なカメラのことですね。記録に残っています。","ENG":"You must mean that strange camera that summoned a Demon-Type C.O. There remains a record of it in my log files.","TWN":"原來是指那個曾經召喚出惡魔型侵蝕體的奇怪相機。我還留有紀錄。"},"stage":{"bg":"CORRIDOR_04","bgm":"THEMA_PRYDWEN","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"SPIRA_CORRUPT_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"네. 멸망한 세계의 <color=#ffd34c>특정 피사체</color>들을 일시적으로 모방하는 아티팩트…… 라고 저희는 추정하고 있죠.","JPN":"はい。滅亡した世界の<color=#ffd34c>特定被写体</color>を一時的にコピーするアーティファクト……と私たちは推測していますわ。","ENG":"That's right. It's an artifact that temporarily imitates <color=#ffd34c>specific objects</color> from extinct worlds… Well, that's our hypothesis anyway.","TWN":"沒錯，我們推測那應該是，可以暫時模仿滅亡世界的<color=#ffd34c>特定拍攝對象</color>的人造神器……"},"stage":{"bg":"CORRIDOR_04","bgm":"THEMA_PRYDWEN","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"SPIRA_CORRUPT_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"가급적 저희가 확보할 수 있길 바라고 있어요. 세상에 돌아다니게 두기에는 위험한 물건이니까요.","JPN":"できれば私たちで確保しておきたいと考えています。放っておくには危険な物ですから。","ENG":"We're hoping to secure it if at all possible. It's far too dangerous to leave it out there in the world.","TWN":"可以的話，希望是由我們來保管，畢竟讓那個東西留在世界上是很危險的。"},"stage":{"bg":"CORRIDOR_04","bgm":"THEMA_PRYDWEN","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"SPIRA_CORRUPT_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"당신들은 믿어도 된다는 말처럼 들리는군요.","JPN":"私たちを信じてほしい、と言っているように聞こえますが。","ENG":"You speak as though you are trying to convince me of your trustworthiness.","TWN":"聽起來似乎可信度滿高的。"},"stage":{"bg":"LIBRARY_01","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"염려 마세요. 신사도 숙녀도, 언변으로 믿음을 얻으려 하지 않는답니다.","JPN":"ご心配なく。紳士も淑女も、口弁で信頼を得ようとはしませんわ。","ENG":"Don't worry. A gentleman does not try to win over hearts with words alone… And neither does a lady.","TWN":"你放心，紳士或淑女，是不會只出一張嘴就想博得信任的。"},"stage":{"bg":"LIBRARY_01","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"행동으로 증명할 따름이죠.","JPN":"行動で証明するのみです。","ENG":"We simply prove ourselves through action.","TWN":"我們會以行動證明。"},"stage":{"bg":"LIBRARY_01","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_03"},{"id":"L35_1","type":"dialog","speaker":"LUCID_BARCODE_NULL_NULL","text":{"KOREA":"버, 벌써 떠나시려는 건가요?","JPN":"も、もう帰られるのですか？","ENG":"L-leaving so soon?","TWN":"你…你要走了嗎？"},"stage":{"bg":"CRUISE","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCID_BARCODE_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}},"sfx":"FX_COMBAT_ALL_FOOT_STEP_LANDING_SMALL"},{"id":"L36_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"그렇습니다만. 대출 상담을 원하십니까, 휴먼.","JPN":"そうです。貸付けの相談をご希望ですか、ヒューマン。","ENG":"Yes. Did you wish to make a loan inquiry, human?","TWN":"沒錯，還是你有資金需求嗎，人類？"},"stage":{"bg":"CRUISE","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"LUCID_BARCODE_NULL_NULL","text":{"KOREA":"아뇨. 돈은 필요하지 않아요. 그런 것보다…….","JPN":"いいえ、お金は要りません。そんなものよりも……","ENG":"No. I don't need money. I was actually hoping to ask…","TWN":"沒有，我不需要錢，只是……"},"stage":{"bg":"CRUISE","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCID_BARCODE_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"LUCID_BARCODE_NULL_NULL","text":{"KOREA":"제가 호라이즌 씨를 따라가면…… 폐가 될까요?!","JPN":"私がホライズンさんについて行くのは……迷惑でしょうか？","ENG":"Will I be a burden if I come with you?","TWN":"我跟你一起去的話……會妨礙你嗎？！"},"stage":{"bg":"CRUISE","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LUCID_BARCODE_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L41_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"네.","JPN":"はい。","ENG":"Yes.","TWN":"會。"},"stage":{"bg":"CRUISE","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LUCID_BARCODE_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L42_1","type":"dialog","speaker":"LUCID_BARCODE_NULL_NULL","text":{"KOREA":"읏, 그렇게 직설적으로 말씀하실 줄은 몰랐는데…….","JPN":"ううっ、そんなストレートに断るなんて思わなかったのに……","ENG":"Aw… I didn't think you'd be so blunt about it…","TWN":"喔，沒想到你會這麼直接地回答我……"},"stage":{"bg":"CRUISE","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LUCID_BARCODE_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L43_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"당신은 저와 동행하기보다 건강을 관리하는 편을 추천드리고 싶군요.","JPN":"あなたには私との同行より、健康管理をおすすめします。","ENG":"I would advise your time is better spent looking after your own health than accompanying me.","TWN":"你與其跟我去，倒不如先做好健康管理吧。"},"stage":{"bg":"CRUISE","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LUCID_BARCODE_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L44_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"저는 유사시 당신에게 의료 서비스를 지원해 드릴 수 있는 기능이 없습니다.","JPN":"私には有事の際、あなたに医療サービスをサポートできる機能がありません。","ENG":"I offer no features that can provide you medical support in an emergency.","TWN":"萬一發生什麼事，我沒有可以提供你急救服務的功能。"},"stage":{"bg":"CRUISE","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LUCID_BARCODE_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L45_1","type":"dialog","speaker":"LUCID_BARCODE_NULL_NULL","text":{"KOREA":"저, 저도 싸움을 도와드릴 수 있어요!","JPN":"わ、私も戦闘ならお役に立てると思います！","ENG":"I-I could help you fight!","TWN":"我…我也想助你一臂之力！"},"stage":{"bg":"CRUISE","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LUCID_BARCODE_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L46_1","type":"dialog","speaker":"LUCID_BARCODE_NULL_NULL","text":{"KOREA":"제가 아니라, 저를 지켜 주려는 아이들이 도와드리겠지만……. 없는 것보다는 나을 거에요.","JPN":"正確には私ではなく、私を守ってくれる子たちのことですが……いないよりはきっとマシだと思います。","ENG":"Well… I won't be doing the fighting, but the children who want to protect me will help… I'm sure it'll be better than nothing.","TWN":"不是我，而是這些保護我的孩子可以幫你……有總比沒有好吧？"},"stage":{"bg":"CRUISE","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LUCID_BARCODE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L47_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"하지만 교사로서 아이들을 인솔할 책임이 있지 않습니까?","JPN":"しかし、教師として子どもたちを引率する責任があるのではないですか？","ENG":"But are you not responsible for your students as their teacher?","TWN":"但身為一位老師，不是有責任要帶領孩子嗎？"},"stage":{"bg":"CRUISE","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"LUCID_BARCODE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L48_1","type":"dialog","speaker":"LUCID_BARCODE_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"…….","TWN":"……"},"stage":{"bg":"CRUISE","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"LUCID_BARCODE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L49_1","type":"dialog","speaker":"LUCID_BARCODE_NULL_NULL","text":{"KOREA":"그 말이 맞아요. 하지만…….","JPN":"おっしゃるとおりです。ですが……","ENG":"True… But the thing is…","TWN":"話是沒錯，可是……"},"stage":{"bg":"CRUISE","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"LUCID_BARCODE_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L50_1","type":"dialog","speaker":"LUCID_BARCODE_NULL_NULL","text":{"KOREA":"사실은 저도, 저 아이들도……. 제프티 바이오테크에서 도망쳐 나온 신세니까요.","JPN":"実は私も、あの子たちも……ジェフティ・バイオテックから逃げてきた身なんです。","ENG":"All those children and I… escaped from Jehuty Biotech.","TWN":"其實我，和那些孩子……我們都是從傑夫堤生物科技逃出來的。"},"stage":{"bg":"CRUISE","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"LUCID_BARCODE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L1_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"…….","TWN":"……"},"stage":{"bg":"CRUISE","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LUCID_BARCODE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L3_1","type":"dialog","speaker":"LUCID_BARCODE_NULL_NULL","text":{"KOREA":"굉장히 친절한 분을 만나서 지금은 이렇게 지내고 있지만…….","JPN":"とても親切な方に出会えて、今はこうやって平和に過ごしていますが……","ENG":"Although we were lucky enough to meet a kindred spirit to enjoy this comfort…","TWN":"雖然遇到一位非常好心的人，我們才可以像現在這樣……"},"stage":{"bg":"CRUISE","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCID_BARCODE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"LUCID_BARCODE_NULL_NULL","text":{"KOREA":"저는, 저 아이들이, 그리고 저처럼 실험체로 쓰였던 아이들이 겪었던 일을…….","JPN":"私はあの子たちが、そして私と同じく実験体として使われた子たちが経験したことを……","ENG":"I have never forgotten what children like them and me had to endure as test subjects…","TWN":"但我和這些孩子，還有那些和我一樣成為實驗體的孩子……"},"stage":{"bg":"CRUISE","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCID_BARCODE_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"LUCID_BARCODE_NULL_NULL","text":{"KOREA":"한 순간도 잊은 적이 없어요.","JPN":"一度も忘れたことがありません。","ENG":"Not for a single moment.","TWN":"從未忘記過我們經歷過的事。"},"stage":{"bg":"CRUISE","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCID_BARCODE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"알고 있었습니다. 당신들의 생체 정보가 연구 시설 데이터베이스에 존재했으니까요.","JPN":"それは認知していました。あなたたちの生体情報は研究施設のデータベースに存在していました。","ENG":"I am already aware of that. Your biometric data was stored in the research facility's database.","TWN":"我知道，研究設施的資料庫裡有你們的生物資訊。"},"stage":{"bg":"CRUISE","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"그래서, 당신은 제프티 바이오테크에 복수하고 싶습니까.","JPN":"それで、あなたはジェフティ・バイオテックに復讐したいのですか。","ENG":"So, is it revenge you seek against Jehuty Biotech?","TWN":"意思是，你想向傑夫堤生物科技報仇嗎？"},"stage":{"bg":"CRUISE","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"LUCID_BARCODE_NULL_NULL","text":{"KOREA":"……네. 저 아이들은 아무것도 몰랐으면 하니까요.","JPN":"……はい。あの子たちには、ずっと知らないままでいてほしいからです。","ENG":"…Yes. Because I hope those kids never have to find out.","TWN":"……是，因為我不希望孩子們知道這些事。"},"stage":{"bg":"CRUISE","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCID_BARCODE_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"LUCID_BARCODE_NULL_NULL","text":{"KOREA":"저 아이들이 더 세상을 알기 전에, 그래서 언젠가 자기들이 얼마나 끔찍한 일을 겪었는지 알게 되기 전에…….","JPN":"あの子たちが世の中を知っていく前に、\\nいつか自分たちがどれほどひどい目にあっていたのか気づく前に……","ENG":"Before those children learn more about the world and in turn realize what horrors were done to them…","TWN":"在孩子們更認識世界之前，在他們發現原來經歷過那麼可怕的事之前……"},"stage":{"bg":"CRUISE","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCID_BARCODE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"LUCID_BARCODE_NULL_NULL","text":{"KOREA":"없어졌으면 좋겠어요. 저 아이들이 평생 동안 누군가를 미워하고 원망하지 않게.","JPN":"あの会社は無くなってほしいんです。あの子たちが一生誰かを憎み恨まないためにも。","ENG":"I hope Jehuty gets wiped off the planet. So those children won't end up spending their entire lives despising someone.","TWN":"我希望可以先弭平這件事，讓孩子們不要一輩子都在怨恨中度過。"},"stage":{"bg":"CRUISE","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCID_BARCODE_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"그렇다면 당신은 저와 함께할 수 없습니다. 휴먼.","JPN":"そのような理由なら、あなたは私と同行することはできません、ヒューマン。","ENG":"That's all the more reason why you cannot accompany me, human.","TWN":"那你更不能與我同行，人類。"},"stage":{"bg":"CRUISE","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"LUCID_BARCODE_NULL_NULL","text":{"KOREA":"네……? 어, 어째서요?","JPN":"はい……？　ど、どうしてですか？","ENG":"Sorry…? H-how come?","TWN":"嗯……？為什麼？"},"stage":{"bg":"CRUISE","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCID_BARCODE_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"당신은 복수를 원한 적이 없습니다. 저 아이들을 세상으로부터 지켜 주고 싶을 뿐이죠.","JPN":"あなたは復讐を望んでいません。あの子たちをこの世の中から守ってあげたいだけです。","ENG":"You never truly wanted revenge. All you desire is to shelter those children from the world.","TWN":"因為你並不是想報仇，你只是想保護那些孩子而已。"},"stage":{"bg":"CRUISE","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"LUCID_BARCODE_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L16_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"아이들은 행복해 보이더군요. 당신은 지금의 삶이 행복합니까?","JPN":"子どもたちは幸せそうでしたね。あなたは今の人生が幸せですか？","ENG":"The children seemed happy enough. But are you happy with your current life?","TWN":"孩子們現在看起來很幸福，那你現在幸福嗎？"},"stage":{"bg":"CRUISE","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LUCID_BARCODE_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L17_1","type":"dialog","speaker":"LUCID_BARCODE_NULL_NULL","text":{"KOREA":"…………네. 하루하루가 무척, 행복하고 소중해요.","JPN":"……はい。毎日がとても幸せで、大切です。","ENG":"…Yes. Every moment is so precious and filled with joy.","TWN":"…………是，我每一天都非常幸福。"},"stage":{"bg":"CRUISE","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LUCID_BARCODE_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L18_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"그렇다면 그 시간을 저 아이들과 더 많이 나눠 주십시오.","JPN":"ならばその時間を、あの子たちにもっとたくさん分けてあげてください。","ENG":"Then spend your time sharing that delight with those children.","TWN":"這樣的話，那你還是把時間花在和孩子們相處上吧"},"stage":{"bg":"CRUISE","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LUCID_BARCODE_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L19_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"시간은 귀중한 재화입니다. 그리고 재화가 많은 휴먼은 대부분 행복해하더군요.","JPN":"時間は貴重な財貨です。そしてその財貨が多いヒューマンほど、幸せそうに暮らしていました。","ENG":"Time is a precious commodity. Most humans plentiful in commodities seem to be happy.","TWN":"時間是非常寶貴的資產，而資產多的人類通常都是幸福的。"},"stage":{"bg":"CRUISE","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LUCID_BARCODE_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L21_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"당신은 당신의 적들도 연민하고 괴로워할 휴먼입니다.","JPN":"あなたは自分の敵でさえ憐憫の情を覚えるヒューマンです。","ENG":"You are someone who would sympathize with and mourn over your enemies.","TWN":"你是會為敵人感到可憐和傷心的人類。"},"stage":{"bg":"CRUISE","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"고통을 자처하느라 저 아이들에게 나눠 줄 행복도 허비하지 마십시오.","JPN":"自らの苦悶のために、あの子たちに与える幸せまで無駄にしないでください。","ENG":"Do not squander the happiness you can share with those children by insisting on bringing suffering upon yourself.","TWN":"為何要自討苦吃，而浪費掉可以和孩子們相處的幸福時間？"},"stage":{"bg":"CRUISE","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"저는 이만 떠날 예정입니다, 휴먼.","JPN":"私はそろそろここを発ちます、ヒューマン。","ENG":"I will leave presently, human.","TWN":"我要走了，人類。"},"stage":{"bg":"CRUISE","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"그래도 당신들 덕분에 방법론을 수정할 기회가 생겼으니, 무작정 막지는 않겠습니다.","JPN":"ですが、あなたたちのおかげで方法論を修正する機会ができたので、むやみに止めることはしません。","ENG":"But as I have gained the chance to modify my methodology thanks to you, I won't stop you from joining me.","TWN":"不過托你們的福，讓我有修改方法論的機會，所以我不會一昧地阻止你。"},"stage":{"bg":"CRUISE","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"피 묻은 손으로 아이들을 안을 자신이 있다면, 절 건져 온 침식체를 다시 불러와서 동행하시죠.","JPN":"血に染まった手であの子たちを抱きしめる覚悟があるなら、私を引き揚げた侵食体とともに同行しても構いません。","ENG":"If you are confident you will not regret holding those children with bloodstained hands, you may join me alongside that C.O. who plucked me out of the water.","TWN":"如果你確定，你能用沾滿鮮血的雙手擁抱孩子們，那就再次召喚那個把我打撈起來的侵蝕體，和我一起走吧。"},"stage":{"bg":"CRUISE","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"LUCID_BARCODE_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"…….","TWN":"……"},"stage":{"bg":"CRUISE","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCID_BARCODE_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"LUCID_BARCODE_NULL_NULL","text":{"KOREA":"미안해요. 호라이즌 씨.","JPN":"すみません、ホライズンさん。","ENG":"I'm sorry… Ms. Horizon.","TWN":"地平線小姐，很抱歉……"},"stage":{"bg":"CRUISE","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCID_BARCODE_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"LUCID_BARCODE_NULL_NULL","text":{"KOREA":"저도 조금은…… 이기적인가 봐요.","JPN":"私も少し……わがままを言ったようです。","ENG":"I'm afraid… I'm rather selfish.","TWN":"我可能……也是自私的。"},"stage":{"bg":"CRUISE","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCID_BARCODE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"RYAN_PRYDWEN_NULL_NULL","text":{"KOREA":"아가씨, 손님이 배에서 내리셨습니다. 수영으로 육지까지 갈 작정이더군요.","JPN":"お嬢様、お客様が船から降りました。泳いで陸地まで向かうようです。","ENG":"My Lady, the guest has disembarked the ship. It appears she plans to swim ashore.","TWN":"小姐，客人下船了，看來她是打算用游的游上岸。"},"stage":{"bg":"LIBRARY_01","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RYAN_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE"},{"id":"L37_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"그래요. 저희는 조금 더 바닷바람을 즐기다 출발하기로 하죠.","JPN":"そうですか。私たちはもう少し潮風を楽しんでから出発することにしましょう。","ENG":"I see. Let us enjoy the ocean breeze for few more minutes before we depart.","TWN":"是嗎？那我們就再吹一下海風再出發吧。"},"stage":{"bg":"LIBRARY_01","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RYAN_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L38_1","type":"dialog","speaker":"RYAN_PRYDWEN_NULL_NULL","text":{"KOREA":"하지만…… 정말 정보를 넘겨 주셔도 괜찮으시겠습니까?","JPN":"しかし……本当に情報を渡してもよかったのでしょうか？","ENG":"But… Are you sure you want to turn over all the information?","TWN":"不過……把情報透漏給她真的沒問題嗎？"},"stage":{"bg":"LIBRARY_01","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RYAN_PRYDWEN_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L39_1","type":"dialog","speaker":"RYAN_PRYDWEN_NULL_NULL","text":{"KOREA":"배에 적재되어 있던 이터니움을 모두 투입해도 2% 남짓한 동력에 불과했습니다.","JPN":"船に積載されていたエタニウムをすべて投入しても、2%弱の動力にしかなりませんでした。","ENG":"We used an entire shipload of Eternium to charge her, but that amounted to merely 2% of total power at most.","TWN":"就算投入船上所有的永恆之金，動能也不過就區區2%而已。"},"stage":{"bg":"LIBRARY_01","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RYAN_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L40_1","type":"dialog","speaker":"RYAN_PRYDWEN_NULL_NULL","text":{"KOREA":"자칫 길을 잘못 들었다간 상황이 곤란해질지도 모릅니다.","JPN":"ともすれば困難な状況になるかもしれません。","ENG":"We may put ourselves in a difficult position if we do not tread carefully.","TWN":"萬一出什麼差錯，情況可能會變得很艱難。"},"stage":{"bg":"LIBRARY_01","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RYAN_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L41_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"믿어 보기로 하죠. 자신의 한계를 안다는 것이 기계의 장점이니까요.","JPN":"信じてみましょう。自身の限界を知っていることが機械の長所ですから。","ENG":"Let's give her the benefit of the doubt for now. After all, the greatest strength of machines lies in their ability to know their limits.","TWN":"就相信她吧。機器人最大的優點，就是清楚自己的極限到哪裡。"},"stage":{"bg":"LIBRARY_01","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RYAN_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L44_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"가기 전에, 한 가지 요청드리겠습니다. 정보료는 추후 청구하십시오.","JPN":"発つ前に、1点要請があります。情報料は後日請求してください。","ENG":"I have one request to make before I depart. You may bill me later for the information.","TWN":"離開前我有件要麻煩你，請之後再跟我請款索取情報的費用。"},"stage":{"bg":"LIBRARY_01","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"제프티 바이오테크가 소유한 연구 시설들의 위치를 희망합니다.","JPN":"ジェフティ・バイオテックが所有する研究施設の位置情報を希望します。","ENG":"I wish to know the locations of research facilities owned by Jehuty Biotech.","TWN":"我想知道傑夫堤生物科技所有研究設施的位置。"},"stage":{"bg":"LIBRARY_01","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"……솔직하지 못한 로봇이라.","JPN":"……素直になれないロボットですか。","ENG":"…A dishonest robot, huh.","TWN":"……真是不坦率的機器人。"},"stage":{"bg":"LIBRARY_01","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"한 번쯤은 오래된 목소리도 실수를 하길 기대하고 있었는데, 아쉽게 됐어요.","JPN":"一度くらいは古き声が過ちを犯すことを楽しみにしていましたが、残念でしたわ。","ENG":"I was hoping the Old Voice would make a mistake for a change. Too bad.","TWN":"原本還期待老聲音起碼可以出一次錯的，真可惜。"},"stage":{"bg":"LIBRARY_01","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};